namespace sv_3f7969990f064ad2b9858cc6b8755e11.Services;

public class ValidationError
{
    public string FieldName { get; set; } = string.Empty;
    public string ErrorMessage { get; set; } = string.Empty;
}

public class ValidationResult
{
    public bool IsValid => Errors.Count == 0;
    public List<ValidationError> Errors { get; set; } = new();
}

public interface IAppointmentService
{
    Task<List<string>> GetDoctorsAsync();
    Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date);
    Task<ValidationResult> ValidatePatientAsync(string email, string insuranceProvider, string doctor, string timeSlot);
}

public class AppointmentService : IAppointmentService
{
    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>
        {
            "Dr. Smith",
            "Dr. Johnson",
            "Dr. Williams",
            "Dr. Brown",
            "Dr. Davis"
        });
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        var slots = new List<string>
        {
            "9:00 AM",
            "9:30 AM",
            "10:00 AM",
            "10:30 AM",
            "11:00 AM",
            "1:00 PM",
            "1:30 PM",
            "2:00 PM",
            "2:30 PM",
            "3:00 PM"
        };

        return Task.FromResult(slots);
    }

    public Task<ValidationResult> ValidatePatientAsync(string email, string insuranceProvider, string doctor, string timeSlot)
    {
        var result = new ValidationResult();

        // Reject "taken@example.com" for outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors.Add(new ValidationError
            {
                FieldName = nameof(email),
                ErrorMessage = "Account has outstanding balance"
            });
        }

        // Reject "None" insurance with "Dr. Smith"
        if (string.Equals(insuranceProvider, "None", StringComparison.OrdinalIgnoreCase)
            && string.Equals(doctor, "Dr. Smith", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors.Add(new ValidationError
            {
                FieldName = nameof(doctor),
                ErrorMessage = "Selected doctor does not accept self-pay patients"
            });
        }

        // Reject "10:00 AM" as taken (simulates race condition)
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.OrdinalIgnoreCase))
        {
            result.Errors.Add(new ValidationError
            {
                FieldName = nameof(timeSlot),
                ErrorMessage = "This slot is no longer available"
            });
        }

        return Task.FromResult(result);
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_3f7969990f064ad2b9858cc6b8755e11.Services
@inject IAppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h1>Book an Appointment</h1>

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* STEP 1: Patient Information *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label for="patientName" class="form-label">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
            @if (!string.IsNullOrEmpty(serverEmailError))
            {
                <div class="validation-message">@serverEmailError</div>
            }
        </div>

        <div class="mb-3">
            <label for="phone" class="form-label">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label for="insurance" class="form-label">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
        }
    </fieldset>

    @* STEP 2: Appointment Details *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label for="doctor" class="form-label">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="Model.Doctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.Doctor" />
                @if (!string.IsNullOrEmpty(serverDoctorError))
                {
                    <div class="validation-message">@serverDoctorError</div>
                }
            </div>

            <div class="mb-3">
                <label for="date" class="form-label">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="Model.AppointmentDate" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label for="timeslot" class="form-label">Time Slot</label>
                @if (timeSlots.Count > 0)
                {
                    <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot">
                        <option value="">-- Select --</option>
                        @foreach (var slot in timeSlots)
                        {
                            <option value="@slot">@slot</option>
                        }
                    </InputSelect>
                }
                else
                {
                    <InputSelect id="timeslot" class="form-select" @bind-Value="Model.TimeSlot" disabled>
                        <option value="">-- Select doctor and date first --</option>
                    </InputSelect>
                }
                <ValidationMessage For="() => Model.TimeSlot" />
                @if (!string.IsNullOrEmpty(serverTimeSlotError))
                {
                    <div class="validation-message">@serverTimeSlotError</div>
                }
            </div>

            <div class="mb-3">
                <label for="reason" class="form-label">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="LoadTimeSlots">Load Time Slots</button>
            <button type="button" class="btn btn-warning me-2" @onclick="CheckAvailability">Check Availability</button>
            <button type="submit" class="btn btn-success">Book Appointment</button>
        </fieldset>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private bool showStep2;
    private bool bookingConfirmed;
    private List<string> doctors = new();
    private List<string> timeSlots = new();

    private string? serverEmailError;
    private string? serverDoctorError;
    private string? serverTimeSlotError;

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        // Validate step 1 fields manually
        editContext = new EditContext(Model);
        var validationMessageStore = new ValidationMessageStore(editContext);

        bool step1Valid = true;

        if (string.IsNullOrWhiteSpace(Model.PatientName))
            step1Valid = false;
        if (string.IsNullOrWhiteSpace(Model.Email) || !Model.Email.Contains('@'))
            step1Valid = false;
        if (string.IsNullOrWhiteSpace(Model.Phone))
            step1Valid = false;
        if (string.IsNullOrWhiteSpace(Model.InsuranceProvider))
            step1Valid = false;

        if (step1Valid)
        {
            showStep2 = true;
        }
    }

    private async Task LoadTimeSlots()
    {
        if (!string.IsNullOrEmpty(Model.Doctor) && Model.AppointmentDate.HasValue)
        {
            timeSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                Model.Doctor,
                DateOnly.FromDateTime(Model.AppointmentDate.Value));
        }
    }

    private async Task CheckAvailability()
    {
        // Clear previous server errors
        serverEmailError = null;
        serverDoctorError = null;
        serverTimeSlotError = null;

        var result = await AppointmentService.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.Doctor ?? string.Empty,
            Model.TimeSlot ?? string.Empty);

        if (!result.IsValid)
        {
            foreach (var error in result.Errors)
            {
                switch (error.FieldName)
                {
                    case "email":
                        serverEmailError = error.ErrorMessage;
                        break;
                    case "doctor":
                        serverDoctorError = error.ErrorMessage;
                        break;
                    case "timeSlot":
                        serverTimeSlotError = error.ErrorMessage;
                        break;
                }
            }
        }
    }

    private void HandleSubmit()
    {
        bookingConfirmed = true;
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_3f7969990f064ad2b9858cc6b8755e11.Models;

public class AppointmentModel
{
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    [Required(ErrorMessage = "Preferred doctor is required.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateTime? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Time slot is required.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or less.")]
    public string? ReasonForVisit { get; set; }
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override System.ComponentModel.DataAnnotations.ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateTime date)
        {
            if (date.Date <= DateTime.Today)
            {
                return new System.ComponentModel.DataAnnotations.ValidationResult(ErrorMessage);
            }
        }
        return System.ComponentModel.DataAnnotations.ValidationResult.Success;
    }
}

